  7→import { buildTrussCopyOrigins, resolveTrussLayout } from '@/truss/layout';
  8→import { buildTrussProfile } from '@/truss/profile';
  9→import { getTopChordRunLength, sampleTopChordRunMidpoint } from '@/truss/curveSampling';
 10→import { buildTrussPurlinAttachments, createDetailPurlinMarker } from '@/truss/purlins';
 11→import {
 12→  getDisplayedAxis,
 13→  getSafeAxis,
 14→  normalizePlanLengthScale,
 15→  normalizePlanOffset,
 16→  normalizeSignedRotationDegrees,
 17→  projectAlongAxis,
