 21→const DETAIL_PADDING_X = 800;
 22→const DETAIL_PADDING_Z = 900;
 23→const DEFAULT_CHORD_THICKNESS = 90;
 24→const DEFAULT_WEB_THICKNESS = 60;
 25→const DEFAULT_PURLIN_MARKER_LENGTH = 180;
 26→const DETAIL_OVERHANG_OFFSET = 260;
 27→const DETAIL_PANEL_OFFSET = 520;
 28→const DETAIL_SPAN_OFFSET = 860;
 29→const DETAIL_RISE_OUTSET = 760;
 30→const DETAIL_PURLIN_OFFSET = 260;
 31→const DETAIL_PURLIN_START_OFFSET = 520;
 32→const DETAIL_WEB_TAG_OFFSET = 320;
 33→const DETAIL_WEB_TAG_TANGENT_SHIFT = 96;
 34→const DETAIL_TOP_CHORD_TAG_OFFSET = 400;
 35→const DETAIL_TAG_OUTSET = 280;
 36→const DETAIL_TAG_HEIGHT = 150;
 37→const DETAIL_TAG_FONT_SIZE = 110;
 38→const DETAIL_TAG_LINE_HEIGHT = 134;
 39→const DETAIL_TAG_MASK_PADDING_X = 64;
 40→const DETAIL_TAG_MASK_PADDING_Y = 36;
