486→function createSegmentDescriptor(id, trussSystem, instance, member, copy) {
487→  const material = normalizeMaterial(instance?.material || 'timber');
488→  return {
489→    id,
490→    kind: 'trussInstance',
491→    geometry: 'segment3d',
492→    start: {
493→      x: member.startWorld.x,
494→      y: member.startWorld.elevation,
495→      z: member.startWorld.y,
496→    },
497→    end: {
498→      x: member.endWorld.x,
499→      y: member.endWorld.elevation,
500→      z: member.endWorld.y,
501→    },
502→    thickness: member.memberType === 'web' ? DEFAULT_WEB_THICKNESS : DEFAULT_CHORD_THICKNESS,
503→    materialKey: getTrussMemberMaterialKey(member.memberType, material),
504→    metadata: {
505→      sourceId: instance.id,
506→      trussSystemId: trussSystem.id,
507→      floorId: trussSystem.floorId,
508→      copyId: copy.id,
509→      memberType: member.memberType,
510→      material,
511→    },
512→    bounds: {
513→      minX: Math.min(member.startWorld.x, member.endWorld.x),
514→      maxX: Math.max(member.startWorld.x, member.endWorld.x),
515→      minY: Math.min(member.startWorld.y, member.endWorld.y),
516→      maxY: Math.max(member.startWorld.y, member.endWorld.y),
517→      minElevation: Math.min(member.startWorld.elevation, member.endWorld.elevation),
518→      maxElevation: Math.max(member.startWorld.elevation, member.endWorld.elevation),
519→    },
520→  };
521→}
522→
523→function createPurlinSegmentDescriptor(segment, trussSystem, instance) {
524→  return {
525→    id: segment.id,
526→    kind: 'trussInstance',
527→    geometry: 'segment3d',
528→    start: {
529→      x: segment.startWorld.x,
530→      y: segment.startWorld.elevation,
531→      z: segment.startWorld.y,
532→    },
533→    end: {
534→      x: segment.endWorld.x,
535→      y: segment.endWorld.elevation,
536→      z: segment.endWorld.y,
537→    },
538→    thickness: segment.thickness,
539→    crossSection: segment.crossSection,
540→    materialKey: segment.materialKey,
541→    metadata: {
542→      ...segment.metadata,
543→      sourceId: instance.id,
544→      trussSystemId: trussSystem.id,
545→      floorId: trussSystem.floorId,
546→    },
547→    bounds: segment.bounds,
548→  };
549→}
550→
551→function createDetailPoint(point) {
552→  return {
553→    x: point.x,
554→    y: -point.z,
555→  };
556→}
557→
558→function detailPolylineLength(points = []) {
559→  let total = 0;
560→  for (let index = 0; index < points.length - 1; index += 1) {
561→    total += Math.hypot(points[index + 1].x - points[index].x, points[index + 1].y - points[index].y);
562→  }
563→  return total;
564→}
565→
566→function worldSegmentLength(startWorld, endWorld) {
567→  if (!startWorld || !endWorld) return 0;
568→  return Math.hypot(
569→    endWorld.x - startWorld.x,
570→    endWorld.y - startWorld.y,
571→    (endWorld.elevation || 0) - (startWorld.elevation || 0)
572→  );
573→}
574→
575→function measurePurlinRunLength(run = null) {
576→  if (!run) return 0;
577→  if (run.segments?.length) {
578→    return run.segments.reduce((total, segment) => (
579→      total + worldSegmentLength(segment.startWorld, segment.endWorld)
580→    ), 0);
581→  }
582→  return detailPolylineLength(run.points || []);
583→}
584→
585→function detailPolylineMidpoint(points = []) {
586→  if (!points.length) return { x: 0, y: 0 };
587→  if (points.length === 1) return points[0];
588→
589→  const totalLength = detailPolylineLength(points);
590→  if (totalLength <= 1e-6) {
591→    return {
592→      x: (points[0].x + points[points.length - 1].x) / 2,
593→      y: (points[0].y + points[points.length - 1].y) / 2,
594→    };
595→  }
